sql:
SELECT song_title, genre_id
FROM songs
WHERE explicit_content = 1 AND genre_id = 1;

SELECT style_name 
FROM song_styles 
WHERE style_id = 1;

SELECT method_name, performance_metric, version
FROM automated_methods
WHERE performance_metric > 0.8;

SELECT song_title
FROM songs
WHERE song_id NOT IN (SELECT song_id FROM playlist_songs);

external_knowledge:
- "musical treasures" refers to songs;
- "the vast ocean of genres" refers to the specified genre with genre_id = 1;
- "serene waves of respectability and popularity" implies the song does not contain explicit content and has a high ranking position;
- "gems of the 21st century" means the songs are ranked between the years 2000 and 2022;
- "untainted by explicit content" means the songs do not have explicit content (explicit_content = 0);
- "glowing with a unique luster in the realm of 3-minute melodies" means the songs have a duration between 180 and 300 seconds;
- "golden threads of accuracy and analysis" refers to high confidence scores (average > 0.8) in automated analysis results;
- "whispered into playlists by their guardians" refers to the users who have added these songs to their playlists, indicating they are well-received and curated.

- 'melody to grace our ears' refers to the first song in the musical collection;
- 'name' refers to the song_title;
- 'length of the journey' is a metaphor for the duration of the song;
- 'musical voyage' refers to the collection or database of songs;
- The first song in the musical voyage corresponds to song_id = 1.

sql:
SELECT song_title, duration
FROM songs
WHERE song_id = 1;

SELECT artist, AVG(explicit_content) AS average_explicit_content
FROM songs
GROUP BY artist;

